form:Form.form:Scripts:
		function onLoad()
{
if(Ctrl('first_filter').GetXValue()=="1")
		{
			Ctrl('cbxMostrar').SetXValue(3);	
	  }
}

//Generar la lista de Numeros
function WhereNros()
{                      
	var listNros,Where,t,subTxt,aux0,aux1;

 	Where="";

	listNros=Ctrl('listNros').GetXValue();
	if (listNros!="")
	{
		listNros=Replace(listNros,",",";").split(";");

		for (t=0; t<listNros.length; t++)
		{ 
			if (listNros[t].indexOf("-")>=0)
			{  
				subTxt=listNros[t].split("-");
				aux0=parseInt(subTxt[0],10);
				aux1=parseInt(subTxt[1],10);

     		if ((!isNaN(aux0)) || (!isNaN(aux1)))
     		{
	     		if (Where!="") Where+=" OR ";
					Where+="(";
						if (!isNaN(aux0)) Where+="STRING2NUMBER(t0.oi_carpeta) >="+aux0;
						if ((!isNaN(aux0)) && (!isNaN(aux1))) Where+=" AND ";
						if (!isNaN(aux1)) Where+="STRING2NUMBER(t0.oi_carpeta) <="+aux1;
					Where+=")";
				}
			} else
			{                           
				aux0=parseInt(listNros[t],10);
				if (!isNaN(aux0)) 
				{
					if (Where!="") Where+=" OR ";
					Where+="STRING2NUMBER(t0.oi_carpeta)="+ aux0;
				}
			}
		}
	}

	if (Where=="" && Ctrl('listNros').GetXValue()!="") Where="1=2";
	Ctrl("nrosWhere").SetXValue(Where);
	//exec_qry();
}

//Generar la lista de Códigos
function WhereCods()
{                      
	var listCods,Where,t,subTxt,aux0,aux1;

 	Where="";

