     		if ((!isNaN(aux0)) || (!isNaN(aux1)))
     		{
	     		if (Where!="") Where+=" OR ";
					Where+="(";
						if (!isNaN(aux0)) Where+="STRING2NUMBER(t0.c_carpeta) >="+aux0;
