				{
					if (Where!="") Where+=" OR ";
					Where+="STRING2NUMBER(t0.c_carpeta)="+ aux0;
				}
			}
		}
	}

	if (Where=="" && Ctrl('listCods').GetXValue()!="") Where="1=2";
	Ctrl("codsWhere").SetXValue(Where);
	//exec_qry();
}

function FILTRAR()
{
	Ctrl("main").DoEvent("FILTER");
}   


function ClearTIPOSCARPETAS()
{
	Ctrl("TIPOSCARPETAS").DelAllRow();
	Ctrl("TiposCarpetasLista").Refresh();
}

function FullTIPOSCARPETAS()
{
	Ctrl("TIPOSCARPETAS").DelAllRow();     
	for (var t=0; t<Ctrl("TiposCarpetasLista").TotalRowsCount(); t++)
		Ctrl("TIPOSCARPETAS").AddRow().SetAttr("id", Ctrl("TiposCarpetasLista").GetAttrValue(t, "id"));

	Ctrl("TiposCarpetasLista").Refresh();
}
